<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #121212;
    color: #e0e0e0;
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    padding: 20px;
  }
  h1 {
    margin-bottom: 16px;
    font-weight: 300;
    letter-spacing: 3px;
    color: #999;
    font-size: 1.4em;
  }
  #controls {
    display: flex;
    gap: 8px;
    margin-bottom: 16px;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    background: #2a2a2a;
    color: #ccc;
    border: none;
    padding: 10px 18px;
    border-radius: 4px;
    cursor: pointer;
    font-size: 13px;
    font-weight: 500;
    letter-spacing: 0.5px;
    transition: all 0.15s ease;
    box-shadow: 0 2px 6px rgba(0,0,0,0.4);
    text-transform: uppercase;
  }
  button:hover { background: #3a3a3a; color: #fff; }
  button.active {
    background: #3a3a3a;
    box-shadow: 0 0 0 2px #5c9ce6, 0 2px 6px rgba(0,0,0,0.4);
    color: #fff;
  }
  button#clear {
    background: #b71c1c;
    color: #fff;
  }
  button#clear:hover { background: #d32f2f; }
  #sand {
    border: 2px solid #333;
    border-radius: 4px;
    cursor: crosshair;
    box-shadow: 0 4px 20px rgba(0,0,0,0.6);
    image-rendering: pixelated;
  }
</style>
</head>
<body>
  <h1>FALLING SAND</h1>
  <div id="controls">
    <button id="mat-sand" class="active">Sand</button>
    <button id="mat-water">Water</button>
    <button id="mat-wall">Wall</button>
    <button id="mat-acid">Acid</button>
    <button id="mat-empty">Eraser</button>
    <button id="clear">Clear</button>
  </div>
  <canvas id="sand"></canvas>
<script>
(function() {
  const CELL_SIZE = 5;
  const W = 80;
  const H = 80;

  const canvas = document.getElementById('sand');
  canvas.width = W * CELL_SIZE;
  canvas.height = H * CELL_SIZE;
  const ctx = canvas.getContext('2d');

  const EMPTY = 0, SAND = 1, WATER = 2, WALL = 3, ACID = 4;
  const MAT_NAMES = ['empty', 'sand', 'water', 'wall', 'acid'];
  const MAT_IDS = { empty: EMPTY, sand: SAND, water: WATER, wall: WALL, acid: ACID };

  let grid = new Uint8Array(W * H);
  let currentMaterial = SAND;
  let isPainting = false;
  let brushSize = 3;

  const imageData = ctx.createImageData(canvas.width, canvas.height);
  const data = imageData.data;

  function idx(x, y) { return y * W + x; }

  function getCell(x, y) {
    if (x < 0 || x >= W || y < 0 || y >= H) return WALL;
    return grid[idx(x, y)];
  }

  function setCell(x, y, v) {
    if (x >= 0 && x < W && y >= 0 && y < H) grid[idx(x, y)] = v;
  }

  function tick() {
    for (let y = H - 1; y >= 0; y--) {
      let leftToRight = Math.random() < 0.5;
      for (let i = 0; i < W; i++) {
        let x = leftToRight ? i : W - 1 - i;
        let cell = grid[idx(x, y)];

        if (cell === EMPTY || cell === WALL) continue;

        if (cell === SAND) {
          let below = getCell(x, y + 1);
          if (below === EMPTY) {
            setCell(x, y + 1, SAND);
            setCell(x, y, EMPTY);
          } else if (below === WATER || below === ACID) {
            setCell(x, y + 1, SAND);
            setCell(x, y, below);
          } else {
            let dir = Math.random() < 0.5 ? -1 : 1;
            for (let d = 0; d < 2; d++) {
              let dx = (d === 0) ? dir : -dir;
              let diag = getCell(x + dx, y + 1);
              if (diag === EMPTY) {
                setCell(x + dx, y + 1, SAND);
                setCell(x, y, EMPTY);
                break;
              } else if (diag === WATER || diag === ACID) {
                setCell(x + dx, y + 1, SAND);
                setCell(x, y, diag);
                break;
              }
            }
          }
        } else if (cell === WATER) {
          let below = getCell(x, y + 1);
          if (below === EMPTY) {
            setCell(x, y + 1, WATER);
            setCell(x, y, EMPTY);
          } else {
            let dir = Math.random() < 0.5 ? -1 : 1;
            let moved = false;
            for (let d = 0; d < 2; d++) {
              let dx = (d === 0) ? dir : -dir;
              let diag = getCell(x + dx, y + 1);
              if (diag === EMPTY) {
                setCell(x + dx, y + 1, WATER);
                setCell(x, y, EMPTY);
                moved = true;
                break;
              }
            }
            if (!moved) {
              let dir = Math.random() < 0.5 ? -1 : 1;
              for (let d = 0; d < 2; d++) {
                let dx = (d === 0) ? dir : -dir;
                if (getCell(x + dx, y) === EMPTY) {
                  setCell(x + dx, y, WATER);
                  setCell(x, y, EMPTY);
                  break;
                }
              }
            }
          }
        } else if (cell === ACID) {
          let targets = [];
          if (getCell(x, y + 1) === SAND || getCell(x, y + 1) === WALL) targets.push([x, y + 1]);
          if (getCell(x - 1, y) === SAND || getCell(x - 1, y) === WALL) targets.push([x - 1, y]);
          if (getCell(x + 1, y) === SAND || getCell(x + 1, y) === WALL) targets.push([x + 1, y]);

          if (targets.length > 0) {
            let t = targets[Math.floor(Math.random() * targets.length)];
            setCell(t[0], t[1], EMPTY);
            if (Math.random() < 0.3) {
              setCell(x, y, EMPTY);
              cell = EMPTY;
            }
          }

          if (cell !== EMPTY) {
            let below = getCell(x, y + 1);
            if (below === EMPTY) {
              setCell(x, y + 1, ACID);
              setCell(x, y, EMPTY);
            } else if (below === WATER) {
              setCell(x, y + 1, ACID);
              setCell(x, y, WATER);
            } else {
              let dir = Math.random() < 0.5 ? -1 : 1;
              let moved = false;
              for (let d = 0; d < 2; d++) {
                let dx = (d === 0) ? dir : -dir;
                let diag = getCell(x + dx, y + 1);
                if (diag === EMPTY) {
                  setCell(x + dx, y + 1, ACID);
                  setCell(x, y, EMPTY);
                  moved = true;
                  break;
                } else if (diag === WATER) {
                  setCell(x + dx, y + 1, ACID);
                  setCell(x, y, WATER);
                  moved = true;
                  break;
                }
              }
              if (!moved) {
                let dir = Math.random() < 0.5 ? -1 : 1;
                for (let d = 0; d < 2; d++) {
                  let dx = (d === 0) ? dir : -dir;
                  if (getCell(x + dx, y) === EMPTY) {
                    setCell(x + dx, y, ACID);
                    setCell(x, y, EMPTY);
                    break;
                  }
                }
              }
            }
          }
        }
      }
    }
  }

  function render() {
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        let cell = grid[idx(x, y)];
        let r, g, b;

        switch (cell) {
          case EMPTY: r = 18; g = 18; b = 30; break;
          case SAND: {
            let v = ((x * 7 + y * 13) % 20) - 10;
            r = 210 + v; g = 180 + v; b = 60 + v;
            break;
          }
          case WATER: {
            let v = ((x * 3 + y * 7) % 15) - 7;
            r = 30 + v; g = 100 + v; b = 200 + v;
            break;
          }
          case WALL: {
            let v = ((x * 5 + y * 11) % 10) - 5;
            r = 100 + v; g = 100 + v; b = 100 + v;
            break;
          }
          case ACID: {
            let v = ((x * 11 + y * 3) % 20) - 10;
            r = 50 + v; g = 255; b = 50 + v;
            break;
          }
          default: r = 18; g = 18; b = 30;
        }

        let baseY = y * CELL_SIZE;
        let baseX = x * CELL_SIZE;
        for (let cy = 0; cy < CELL_SIZE; cy++) {
          let rowIdx = (baseY + cy) * canvas.width * 4 + baseX * 4;
          for (let cx = 0; cx < CELL_SIZE; cx++) {
            let pi = rowIdx + cx * 4;
            data[pi] = r;
            data[pi + 1] = g;
            data[pi + 2] = b;
            data[pi + 3] = 255;
          }
        }
      }
    }
    ctx.putImageData(imageData, 0, 0);
  }

  function paint(x, y) {
    let halfBrush = Math.floor(brushSize / 2);
    for (let dy = -halfBrush; dy <= halfBrush; dy++) {
      for (let dx = -halfBrush; dx <= halfBrush; dx++) {
        setCell(x + dx, y + dy, currentMaterial);
      }
    }
  }

  function getCanvasCoords(e) {
    let rect = canvas.getBoundingClientRect();
    let scaleX = canvas.width / rect.width;
    let scaleY = canvas.height / rect.height;
    let clientX, clientY;
    if (e.touches) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }
    return {
      x: Math.floor((clientX - rect.left) * scaleX / CELL_SIZE),
      y: Math.floor((clientY - rect.top) * scaleY / CELL_SIZE)
    };
  }

  canvas.addEventListener('mousedown', function(e) {
    isPainting = true;
    let coords = getCanvasCoords(e);
    paint(coords.x, coords.y);
  });

  canvas.addEventListener('mousemove', function(e) {
    if (!isPainting) return;
    let coords = getCanvasCoords(e);
    paint(coords.x, coords.y);
  });

  canvas.addEventListener('mouseup', function() { isPainting = false; });
  canvas.addEventListener('mouseleave', function() { isPainting = false; });

  canvas.addEventListener('touchstart', function(e) {
    e.preventDefault();
    isPainting = true;
    let coords = getCanvasCoords(e);
    paint(coords.x, coords.y);
  });

  canvas.addEventListener('touchmove', function(e) {
    e.preventDefault();
    if (!isPainting) return;
    let coords = getCanvasCoords(e);
    paint(coords.x, coords.y);
  });

  canvas.addEventListener('touchend', function() { isPainting = false; });

  document.querySelectorAll('#controls button:not(#clear)').forEach(function(btn) {
    btn.addEventListener('click', function() {
      document.querySelectorAll('#controls button:not(#clear)').forEach(function(b) {
        b.classList.remove('active');
      });
      btn.classList.add('active');
      let mat = btn.id.replace('mat-', '');
      currentMaterial = MAT_IDS[mat];
    });
  });

  document.getElementById('clear').addEventListener('click', function() {
    grid.fill(0);
  });

  function loop() {
    tick();
    render();
    requestAnimationFrame(loop);
  }

  render();
  requestAnimationFrame(loop);

  window.sim = {
    w: W,
    h: H,
    tick: function(n) {
      for (let i = 0; i < n; i++) tick();
    },
    get: function(x, y) {
      let cell = getCell(x, y);
      return MAT_NAMES[cell];
    },
    set: function(x, y, material) {
      let matId = MAT_IDS[material];
      if (matId !== undefined) setCell(x, y, matId);
    },
    clear: function() {
      grid.fill(0);
    }
  };
})();
</script>
</body>
</html>
